def simulate_db_delay():
    """Simulate database query latency"""
    time.sleep(0.1)


def generate_cache_key(*args, **kwargs):
    """Generate a consistent cache key from arguments"""
    key_data = json.dumps({'args': args, 'kwargs': kwargs}, sort_keys=True)
    return hashlib.md5(key_data.encode()).hexdigest()


# Cache decorator for general purpose caching
def cached(ttl=300, prefix='cache'):
    """
    Decorator that caches function results in Memcached.
    
    Args:
        ttl: Time to live in seconds (default 300 = 5 minutes)
        prefix: Cache key prefix for namespacing
    """
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            # Generate cache key
            cache_key = f"{prefix}:{func.__name__}:{generate_cache_key(*args, **kwargs)}"
            
            # Try to get from cache
            try:
                cached_result = mc.get(cache_key)
                if cached_result is not None:
                    app.logger.info(f"Cache HIT for key: {cache_key}")
                    cached_result['_cache'] = 'HIT'
                    cached_result['_cache_key'] = cache_key
                    return cached_result
            except Exception as e:
                app.logger.error(f"Cache GET error: {e}")
            
            # Cache miss - execute function
            app.logger.info(f"Cache MISS for key: {cache_key}")
            result = func(*args, **kwargs)
            
            # Store in cache
            try:
                mc.set(cache_key, result, expire=ttl)
                app.logger.info(f"Cached result with key: {cache_key}, TTL: {ttl}s")
            except Exception as e:
                app.logger.error(f"Cache SET error: {e}")
            
            result['_cache'] = 'MISS'
            result['_cache_key'] = cache_key
            return result
        
        return wrapper
    return decorator


# Cache decorator specifically for API responses
def cache_api_response(ttl=60):
    """
    Decorator for caching API endpoint responses based on request path and query params.
    
    Args:
        ttl: Time to live in seconds (default 60 = 1 minute)
    """
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            # Build cache key from request
            query_string = request.query_string.decode('utf-8')
            raw_key = f"api:{request.path}:{query_string}:{json.dumps(kwargs, sort_keys=True)}"
            cache_key = f"api:{hashlib.md5(raw_key.encode()).hexdigest()}"
            
            # Try cache
            try:
                cached_result = mc.get(cache_key)
                if cached_result is not None:
                    app.logger.info(f"API Cache HIT: {cache_key}")
                    response = jsonify(cached_result)
                    response.headers['X-Cache'] = 'HIT'
                    response.headers['X-Cache-Key'] = cache_key
                    return response
            except Exception as e:
                app.logger.error(f"API Cache GET error: {e}")
            
            # Cache miss
            app.logger.info(f"API Cache MISS: {cache_key}")
            result = func(*args, **kwargs)
            
            # If result is a tuple (response, status_code), handle accordingly
            if isinstance(result, tuple):
                response_data, status_code = result
            else:
                response_data = result
                status_code = 200
            
            # Only cache successful responses
            if status_code == 200:
                try:
                    cache_data = response_data if isinstance(response_data, dict) else response_data
                    mc.set(cache_key, cache_data, expire=ttl)
                except Exception as e:
                    app.logger.error(f"API Cache SET error: {e}")
            
            response = jsonify(response_data)
            response.status_code = status_code
            response.headers['X-Cache'] = 'MISS'
            response.headers['X-Cache-Key'] = cache_key
            return response
        
        return wrapper
    return decorator


