# Write-through cache example: Update product and invalidate cache
@app.route('/api/products/<product_id>', methods=['PUT'])
def update_product(product_id):
    """Update a product with cache invalidation (write-through pattern)"""
    if product_id not in FAKE_DATABASE['products']:
        return jsonify({'error': 'Product not found', 'product_id': product_id}), 404
    
    data = request.get_json()
    if not data:
        return jsonify({'error': 'No data provided'}), 400
    
    # Update the "database"
    product = FAKE_DATABASE['products'][product_id]
    for key in ['name', 'price', 'category', 'stock']:
        if key in data:
            product[key] = data[key]
    
    # Invalidate related caches
    try:
        # Invalidate the specific product cache
        product_cache_key = f"db:db_get_product:{generate_cache_key(product_id)}"
        mc.delete(product_cache_key)
        
        # Invalidate category-based caches
        if 'category' in data:
            old_category_key = f"db:db_get_products_by_category:{generate_cache_key(product.get('category', ''))}"
            mc.delete(old_category_key)
            new_category_key = f"db:db_get_products_by_category:{generate_cache_key(data['category'])}"
            mc.delete(new_category_key)
        
        # Invalidate dashboard stats since they include product data
        dashboard_key = f"db:db_get_dashboard_stats:{generate_cache_key()}"
        mc.delete(dashboard_key)
        
        app.logger.info(f"Cache invalidated for product {product_id}")
    except Exception as e:
        app.logger.error(f"Cache invalidation error: {e}")
    
    return jsonify({
        'status': 'updated',
        'data': product,
        'cache_invalidated': True,
        'timestamp': datetime.utcnow().isoformat()
    })


# Batch cache warming endpoint
@app.route('/api/cache/warm', methods=['POST'])
def warm_cache():
    """Pre-populate cache with commonly accessed data"""
    warmed = []
    
    try:
        # Warm user cache
        db_get_all_users()
        warmed.append('all_users')
        
        for user_id in FAKE_DATABASE['users']:
            db_get_user(user_id)
            warmed.append(f'user_{user_id}')
        
        # Warm product cache
        for product_id in FAKE_DATABASE['products']:
            db_get_product(product_id)
            warmed.append(f'product_{product_id}')
        
        # Warm category caches
        categories = set(p['category'] for p in FAKE_DATABASE['products'].values())
        for category in categories:
            db_get_products_by_category(category)
            warmed.append(f'category_{category}')
        
        # Warm dashboard stats
        db_get_dashboard_stats()
        warmed.append('dashboard_stats')
        
        return jsonify({
            'status': 'success',
            'warmed_entries': warmed,
            'count': len(warmed),
            'timestamp': datetime.utcnow().isoformat()
        })
    except Exception as e:
        return jsonify({
            'status': 'error',
            'message': str(e),
            'warmed_entries': warmed
        }), 500


# Health check endpoint
@app.route('/health')
def health_check():
    """Health check including Memcached connectivity"""
    memcache_status = 'unknown'
    try:
        mc.set('health_check', 'ok', expire=10)
        result = mc.get('health_check')
        if result == 'ok':
            memcache_status = 'healthy'
        else:
            memcache_status = 'degraded'
    except Exception as e:
        memcache_status = f'unhealthy: {str(e)}'
    
    overall_status = 'healthy' if memcache_status == 'healthy' else 'degraded'
    status_code = 200 if overall_status == 'healthy' else 503
    
    return jsonify({
        'status': overall_status,
        'components': {
            'app': 'healthy',
            'memcached': memcache_status,
        },
        'timestamp': datetime.utcnow().isoformat()
    }), status_code


